import subprocess
import os
import re
from google.cloud import storage


def process_image(event, context):
    """Cloud Function triggered by Cloud Storage to convert images using ImageMagick.
    
    Args:
        event (dict): Event payload containing Cloud Storage object metadata.
        context (google.cloud.functions.Context): Event context.
    """
    bucket_name = event['bucket']
    file_name = event['name']
    
    # Validate bucket name - must be alphanumeric, hyphens, underscores, dots
    if not re.match(r'^[a-zA-Z0-9._-]+$', bucket_name):
        print(f"Invalid bucket name: {bucket_name}")
        return
    
    # Validate filename - prevent path traversal and command injection
    if not _validate_filename(file_name):
        print(f"Invalid or unsafe filename: {file_name}")
        return
    
    # Extract conversion options from object metadata
    metadata = event.get('metadata', {}) or {}
    
    output_format = metadata.get('output_format', 'png')
    resize = metadata.get('resize', None)
    quality = metadata.get('quality', None)
    
    # Validate output format against allowlist
    allowed_formats = {'png', 'jpg', 'jpeg', 'gif', 'bmp', 'tiff', 'webp'}
    if output_format.lower() not in allowed_formats:
        print(f"Unsupported output format: {output_format}")
        return
    
    # Validate resize parameter if provided (must match WxH pattern)
    if resize and not re.match(r'^\d{1,5}x\d{1,5}$', resize):
        print(f"Invalid resize parameter: {resize}")
        return
    
    # Validate quality parameter if provided (must be integer 1-100)
    if quality is not None:
        try:
            quality_int = int(quality)
            if not 1 <= quality_int <= 100:
                print(f"Quality must be between 1 and 100, got: {quality}")
                return
            quality = str(quality_int)
        except (ValueError, TypeError):
            print(f"Invalid quality parameter: {quality}")
            return
    
    # Determine output filename
    file_base, _ = os.path.splitext(file_name)
    output_file_name = f"{file_base}_converted.{output_format.lower()}"
    
    # Download the source file from Cloud Storage
    storage_client = storage.Client()
    source_bucket = storage_client.bucket(bucket_name)
    source_blob = source_bucket.blob(file_name)
    
    # Use /tmp for Cloud Functions temporary storage
    tmp_input_path = os.path.join('/tmp', os.path.basename(file_name))
    tmp_output_path = os.path.join('/tmp', os.path.basename(output_file_name))
    
    try:
        source_blob.download_to_filename(tmp_input_path)
        print(f"Downloaded {file_name} to {tmp_input_path}")
    except Exception as e:
        print(f"Error downloading file: {e}")
        return
    
    # Build ImageMagick convert command as a list to avoid shell injection
    # Using list form with subprocess prevents shell interpretation of special characters
    cmd = [
        '/usr/bin/convert',  # Use absolute path to ImageMagick binary
        tmp_input_path
    ]
    
    # Add optional parameters
    if resize:
        cmd.extend(['-resize', resize])
    
    if quality:
        cmd.extend(['-quality', quality])
    
    # Limit ImageMagick resource usage to prevent resource exhaustion attacks
    cmd = [
        '/usr/bin/convert',
        '-limit', 'memory', '256MiB',
        '-limit', 'map', '512MiB',
        '-limit', 'disk', '1GiB',
        '-limit', 'time', '60',
        tmp_input_path
    ]
    
    if resize:
        cmd.extend(['-resize', resize])
    
    if quality:
        cmd.extend(['-quality', quality])
    
    cmd.append(tmp_output_path)
    
    print(f"Executing command: {cmd}")
    
    # Use subprocess with list arguments (no shell=True) to prevent command injection
    # Setting a timeout prevents hanging processes
    try:
        result = subprocess.call(
            cmd,
            timeout=120,
            env=_get_sanitized_env()
        )
    except subprocess.TimeoutExpired:
        print("ImageMagick conversion timed out")
        _cleanup_temp_files(tmp_input_path, tmp_output_path)
        return
    except Exception as e:
        print(f"Error executing ImageMagick: {e}")
        _cleanup_temp_files(tmp_input_path, tmp_output_path)
        return
    
    if result != 0:
        print(f"ImageMagick convert failed with return code: {result}")
        _cleanup_temp_files(tmp_input_path, tmp_output_path)
        return
    
    # Upload the converted file back to Cloud Storage
    output_bucket_name = metadata.get('output_bucket', bucket_name)
    
    # Validate output bucket name
    if not re.match(r'^[a-zA-Z0-9._-]+$', output_bucket_name):
        print(f"Invalid output bucket name: {output_bucket_name}")
        _cleanup_temp_files(tmp_input_path, tmp_output_path)
        return
    
    try:
        output_bucket = storage_client.bucket(output_bucket_name)
        output_blob = output_bucket.blob(f"converted/{output_file_name}")
        output_blob.upload_from_filename(tmp_output_path)
        print(f"Uploaded converted file to gs://{output_bucket_name}/converted/{output_file_name}")
    except Exception as e:
        print(f"Error uploading converted file: {e}")
    finally:
        _cleanup_temp_files(tmp_input_path, tmp_output_path)


def _validate_filename(filename):
    """Validate filename to prevent path traversal and injection attacks."""
    if not filename:
        return False
    
    # Reject path traversal attempts
    if '..' in filename or filename.startswith('/'):
        return False
    
    # Reject null bytes
    if '\x00' in filename:
        return False
    
    # Only allow safe characters in filename
    # Allow alphanumeric, hyphens, underscores, dots, and forward slashes (for GCS paths)
    if not re.match(r'^[a-zA-Z0-9._/\- ]+$', filename):
        return False
    
    # Validate file extension against allowed input formats
    allowed_input_extensions = {
        '.png', '.jpg', '.jpeg', '.gif', '.bmp', '.tiff', '.tif', '.webp', '.svg'
    }
    _, ext = os.path.splitext(filename)
    if ext.lower() not in allowed_input_extensions:
        return False
    
    return True


def _get_sanitized_env():
    """Return a sanitized environment for subprocess execution."""
    # Only pass through necessary environment variables
    safe_env = {}
    allowed_env_vars = ['PATH', 'HOME', 'MAGICK_TEMPORARY_PATH', 'MAGICK_MEMORY_LIMIT']
    
    for var in allowed_env_vars:
        if var in os.environ:
            safe_env[var] = os.environ[var]
    
    # Set MAGICK_TEMPORARY_PATH to /tmp for Cloud Functions
    safe_env['MAGICK_TEMPORARY_PATH'] = '/tmp'
    
    # Ensure PATH only contains expected directories
    safe_env['PATH'] = '/usr/local/bin:/usr/bin:/bin'
    
    return safe_env


def _cleanup_temp_files(*file_paths):
    """Safely clean up temporary files."""
    for file_path in file_paths:
        try:
            if os.path.exists(file_path):
                os.remove(file_path)
                print(f"Cleaned up temporary file: {file_path}")
        except OSError as e:
            print(f"Error cleaning up {file_path}: {e}")